sql:
SELECT platform_type, COUNT(*) as total_platforms
FROM platforms
GROUP BY platform_type;

SELECT data_reliability 
FROM oceanographic_data 
WHERE wspn_model_level0 > 5;

external_knowledge:
- 'typical' in this context refers to the statistical average; 
- 'depth measured at the surface' corresponds to 'depth_level0', which is the depth at 0 meters; 
- 'vessel known as the 'Ship Ocean Explorer'' refers to the specific platform named 'Ship Ocean Explorer'.

sql:
SELECT DISTINCT qc.data_id
FROM quality_control qc
WHERE qc.qc_status = 'fail';

SELECT depth_level0, AVG(wspe_model_level0) AS AvgWindSpeed
FROM oceanographic_data
GROUP BY depth_level0;

SELECT "timestamp", "platform_id"
FROM oceanographic_data
WHERE "depth_level1" > 1000 AND "data_id" > 1000;

SELECT data_id, timestamp, latitude
FROM oceanographic_data
WHERE wste_model_level0 > (SELECT AVG(wste_model_level0) FROM oceanographic_data);

external_knowledge:
- Platform ID 1 refers to the first research platform in the database;
- Level one and two refer to different sampling depths for oceanographic data collection;
- The geographical coordinates (latitude and longitude) pinpoint the exact location where the data was collected.

sql:
SELECT temperature
FROM temperatures
WHERE depth_level > 0 AND temperature > 20;

SELECT COUNT(DISTINCT sensor_id) AS NumberOfSensorsWithFailures
FROM oceanographic_data
WHERE data_id IN (SELECT data_id FROM quality_control WHERE qc_status = 'fail');

SELECT data_id, salinity
FROM oceanographic_data
ORDER BY salinity DESC;
